class Solution(object):
    def deepestLeavesSum(self, root):
        from collections import deque
        q = deque([root])
        while q:
            level_sum = 0
            level_size = len(q)
            for _ in range(level_size):
                node = q.popleft()
                level_sum += node.val
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            if not q:
                return level_sum
